 52→//takes pm, fills in min & max
 53→void find_min_max(polymodel* pm, int submodel_num, vms_vector* minv, vms_vector* maxv)
 54→{
 55→	uint16_t nverts;
 56→	vms_vector* vp;
 57→	uint16_t* data, type;
 58→
 59→	data = (uint16_t*)& pm->model_data[pm->submodel_ptrs[submodel_num]];
 60→
 61→	type = *data++;
 62→
 63→	Assert(type == 7 || type == 1);
 64→
 65→	nverts = *data++;
 66→
 67→	if (type == 7)
 68→		data += 2;		//skip start & pad
 69→
 70→	vp = (vms_vector*)data;
 71→
 72→	*minv = *maxv = *vp++; nverts--;
 73→
 74→	while (nverts--) 
 75→	{
 76→		if (vp->x > maxv->x) maxv->x = vp->x;
 77→		if (vp->y > maxv->y) maxv->y = vp->y;
 78→		if (vp->z > maxv->z) maxv->z = vp->z;
 79→
 80→		if (vp->x < minv->x) minv->x = vp->x;
 81→		if (vp->y < minv->y) minv->y = vp->y;
 82→		if (vp->z < minv->z) minv->z = vp->z;
 83→
 84→		vp++;
 85→	}
 86→
 87→}
