 89→#define MORPH_RATE (f1_0*3)
 90→
 91→fix morph_rate = MORPH_RATE;
 92→
 93→void init_points(polymodel* pm, vms_vector* box_size, int submodel_num, morph_data* md)
 94→{
 95→	uint16_t nverts;
 96→	vms_vector* vp;
 97→	uint16_t* data, type;
 98→	int i;
 99→
100→	//printf("initing %d ",submodel_num);
101→
102→	data = (uint16_t*)& pm->model_data[pm->submodel_ptrs[submodel_num]];
103→
104→	type = *data++;
105→	Assert(type == 7 || type == 1);
106→	nverts = *data++;
107→	md->n_morphing_points[submodel_num] = 0;
108→
109→	if (type == 7)
110→	{
111→		i = *data++;		//get start point number
112→		data++;				//skip pad
113→	}
114→	else
115→		i = 0;				//start at zero
116→
117→	Assert(i + nverts < MAX_VECS);
118→
119→	md->submodel_startpoints[submodel_num] = i;
120→
121→	vp = (vms_vector*)data;
122→
123→	while (nverts--) 
124→	{
125→		fix k, dist;
126→
127→		if (box_size) 
128→		{
129→			fix t;
130→
131→			k = 0x7fffffff;
132→
133→			if (vp->x && f2i(box_size->x) < abs(vp->x) / 2 && (t = fixdiv(box_size->x, abs(vp->x))) < k) k = t;
134→			if (vp->y && f2i(box_size->y) < abs(vp->y) / 2 && (t = fixdiv(box_size->y, abs(vp->y))) < k) k = t;
135→			if (vp->z && f2i(box_size->z) < abs(vp->z) / 2 && (t = fixdiv(box_size->z, abs(vp->z))) < k) k = t;
136→
137→			if (k == 0x7fffffff) k = 0;
138→
139→		}
140→		else
141→			k = 0;
142→
143→		vm_vec_copy_scale(&md->morph_vecs[i], vp, k);
144→
145→		dist = vm_vec_normalized_dir_quick(&md->morph_deltas[i], vp, &md->morph_vecs[i]);
146→
147→		md->morph_times[i] = fixdiv(dist, morph_rate);
148→
149→		if (md->morph_times[i] != 0)
150→			md->n_morphing_points[submodel_num]++;
151→
152→		vm_vec_scale(&md->morph_deltas[i], morph_rate);
153→		vp++; i++;
154→	}
155→
156→	//printf("npoints = %d\n",n_morphing_points[submodel_num]);
157→}
