159→void update_points(polymodel* pm, int submodel_num, morph_data* md)
160→{
161→	uint16_t nverts;
162→	vms_vector* vp;
163→	uint16_t* data, type;
164→	int i;
165→
166→	//printf("updating %d ",submodel_num);
167→
168→	data = (uint16_t*)& pm->model_data[pm->submodel_ptrs[submodel_num]];
169→
170→	type = *data++;
171→
172→	Assert(type == 7 || type == 1);
173→
174→	nverts = *data++;
175→
176→	if (type == 7) 
177→	{
178→		i = *data++;		//get start point number
179→		data++;				//skip pad
180→	}
181→	else
182→		i = 0;				//start at zero
183→
184→	vp = (vms_vector*)data;
185→
186→	while (nverts--) 
187→	{
188→		if (md->morph_times[i])		//not done yet
189→			if ((md->morph_times[i] -= FrameTime) <= 0) 
190→			{
191→				md->morph_vecs[i] = *vp;
192→				md->morph_times[i] = 0;
193→				md->n_morphing_points[submodel_num]--;
194→			}
195→			else
196→				vm_vec_scale_add2(&md->morph_vecs[i], &md->morph_deltas[i], FrameTime);
197→		vp++; i++;
198→	}
199→
200→	//printf("npoints = %d\n",n_morphing_points[submodel_num]);
201→}
