204→//process the morphing object for one frame
205→void do_morph_frame(object* obj)
206→{
207→	int i;
208→	polymodel* pm;
209→	morph_data* md;
210→
211→	md = find_morph_data(obj);
212→
213→	if (md == NULL) {					//maybe loaded half-morphed from disk
214→		obj->flags |= OF_SHOULD_BE_DEAD;		//..so kill it
215→		return;
216→	}
217→
218→	pm = &Polygon_models[md->obj->rtype.pobj_info.model_num];
219→
220→	//printf("morph_frame active = ");
221→	//for (i=0;i<pm->n_models;i++)
222→	//	printf("%d ",submodel_active[i]);
223→	//printf("\n");
224→
225→
226→	for (i = 0; i < pm->n_models; i++)
227→		if (md->submodel_active[i] == 1) {
228→
229→			update_points(pm, i, md);
230→
231→			if (md->n_morphing_points[i] == 0) {		//maybe start submodel
232→				int t;
233→
234→				md->submodel_active[i] = 2;		//not animating, just visible
235→
236→				md->n_submodels_active--;		//this one done animating
237→
238→				for (t = 0; t < pm->n_models; t++)
239→					if (pm->submodel_parents[t] == i) {		//start this one
240→
241→						init_points(pm, NULL, t, md);
242→						md->n_submodels_active++;
243→						md->submodel_active[t] = 1;
244→
245→					}
246→			}
247→
248→		}
249→
250→	if (!md->n_submodels_active) {			//done morphing!
251→
252→		md->obj->control_type = md->morph_save_control_type;
253→		md->obj->movement_type = md->morph_save_movement_type;
254→
255→		md->obj->render_type = RT_POLYOBJ;
256→
257→		md->obj->mtype.phys_info = md->morph_save_phys_info;
258→
259→		md->obj = NULL;
260→	}
261→
262→}
