275→//make the object morph
276→void morph_start(object* obj)
277→{
278→	polymodel* pm;
279→	vms_vector pmmin, pmmax;
280→	vms_vector box_size;
281→	int i;
282→	morph_data* md;
283→
284→	for (i = 0; i < MAX_MORPH_OBJECTS; i++)
285→		if (morph_objects[i].obj == NULL || morph_objects[i].obj->type == OBJ_NONE || morph_objects[i].obj->signature != morph_objects[i].Morph_sig)
286→			break;
287→
288→	if (i == MAX_MORPH_OBJECTS)		//no free slots
289→		return;
290→
291→	md = &morph_objects[i];
292→
293→	Assert(obj->render_type == RT_POLYOBJ);
294→
295→	md->obj = obj;
296→	md->Morph_sig = obj->signature;
297→
298→	md->morph_save_control_type = obj->control_type;
299→	md->morph_save_movement_type = obj->movement_type;
300→	md->morph_save_phys_info = obj->mtype.phys_info;
301→
302→	Assert(obj->control_type == CT_AI);		//morph objects are also AI objects
303→
304→	obj->control_type = CT_MORPH;
305→	obj->render_type = RT_MORPH;
306→	obj->movement_type = MT_PHYSICS;		//RT_NONE;
307→
308→	obj->mtype.phys_info.rotvel = morph_rotvel;
309→
310→	pm = &Polygon_models[obj->rtype.pobj_info.model_num];
311→
312→	find_min_max(pm, 0, &pmmin, &pmmax);
313→
314→	box_size.x = std::max(-pmmin.x, pmmax.x) / 2;
315→	box_size.y = std::max(-pmmin.y, pmmax.y) / 2;
316→	box_size.z = std::max(-pmmin.z, pmmax.z) / 2;
317→
318→	for (i = 0; i < MAX_VECS; i++)		//clear all points
319→		md->morph_times[i] = 0;
320→
321→	for (i = 1; i < MAX_SUBMODELS; i++)		//clear all parts
322→		md->submodel_active[i] = 0;
323→
324→	md->submodel_active[0] = 1;		//1 means visible & animating
325→
326→	md->n_submodels_active = 1;
327→
328→	//now, project points onto surface of box
329→
330→	init_points(pm, &box_size, 0, md);
331→
332→}
