334→void draw_model(polymodel* pm, int submodel_num, vms_angvec* anim_angles, fix light, morph_data* md)
335→{
336→	int i, mn;
337→	int facing;
338→	int sort_list[MAX_SUBMODELS], sort_n;
339→
340→	//first, sort the submodels
341→
342→	sort_list[0] = submodel_num;
343→	sort_n = 1;
344→
345→	for (i = 0; i < pm->n_models; i++)
346→
347→		if (md->submodel_active[i] && pm->submodel_parents[i] == submodel_num) 
348→		{
349→
350→			facing = g3_check_normal_facing(&pm->submodel_pnts[i], &pm->submodel_norms[i]);
351→
352→			if (!facing)
353→
354→				sort_list[sort_n++] = i;
355→
356→			else //put at start
357→			{
358→				int t;
359→
360→				for (t = sort_n; t > 0; t--)
361→					sort_list[t] = sort_list[t - 1];
362→
363→				sort_list[0] = i;
364→
365→				sort_n++;
366→			}
367→
368→		}
369→
370→	//now draw everything
371→	for (i = 0; i < sort_n; i++) 
372→	{
373→		mn = sort_list[i];
374→
375→		if (mn == submodel_num) 
376→		{
377→			int i;
378→
379→			for (i = 0; i < pm->n_textures; i++) {
380→				texture_list_index[i] = ObjBitmaps[ObjBitmapPtrs[pm->first_texture + i]];
381→				texture_list[i] = &GameBitmaps[ObjBitmaps[ObjBitmapPtrs[pm->first_texture + i]].index];
382→			}
383→
384→			// Make sure the textures for this object are paged in...
385→			piggy_page_flushed = 0;
386→			for (i = 0; i < pm->n_textures; i++)
387→				PIGGY_PAGE_IN(texture_list_index[i]);
388→			// Hmmm... cache got flushed in the middle of paging all these in,
389→			// so we need to reread them all in.
390→			if (piggy_page_flushed) 
391→			{
392→				piggy_page_flushed = 0;
393→				for (i = 0; i < pm->n_textures; i++)
394→					PIGGY_PAGE_IN(texture_list_index[i]);
395→			}
396→			// Make sure that they can all fit in memory.
397→			Assert(piggy_page_flushed == 0);
398→
399→			g3_draw_morphing_model(&pm->model_data[pm->submodel_ptrs[submodel_num]], texture_list, anim_angles, light, &md->morph_vecs[md->submodel_startpoints[submodel_num]]);
400→
401→		}
402→		else 
403→		{
404→			vms_matrix orient;
405→			vm_angles_2_matrix(&orient, &anim_angles[mn]);
406→			g3_start_instance_matrix(&pm->submodel_offsets[mn], &orient);
407→			draw_model(pm, mn, anim_angles, light, md);
408→			g3_done_instance();
409→		}
410→	}
411→}
