413→void draw_morph_object(object* obj)
414→{
415→	//	int save_light;
416→	polymodel* po;
417→	fix light;
418→	morph_data* md;
419→
420→	md = find_morph_data(obj);
421→	Assert(md != NULL);
422→
423→	Assert(obj->rtype.pobj_info.model_num < N_polygon_models);
424→
425→	po = &Polygon_models[obj->rtype.pobj_info.model_num];
426→
427→	light = compute_object_light(obj, NULL);
428→
429→	g3_start_instance_matrix(&obj->pos, &obj->orient);
430→	g3_set_interp_points(robot_points);
431→
432→	draw_model(po, 0, obj->rtype.pobj_info.anim_angles, light, md);
433→
434→	g3_done_instance();
435→
436→	if (Newdemo_state == ND_STATE_RECORDING)
437→		newdemo_record_morph_frame(md);
438→
439→}
