{
    if (g_effect_ps_write_back_hit_object) {
        int len = Wosize_val(v_packed);
        int32_t buf[16];
        if (len > 16) len = 16;
        for (int i = 0; i < len; i++)
            buf[i] = (int32_t)Long_val(Field(v_packed, i));
        g_effect_ps_write_back_hit_object(buf, len);
