CAMLprim value cd_ox_effect_ps_find_vector_intersection(value v_packed)
{
    CAMLparam1(v_packed);
    CAMLlocal1(v_result);
    int query_len = Wosize_val(v_packed);
    int32_t query[256];
    for (int i = 0; i < query_len && i < 256; i++)
        query[i] = Int_val(Field(v_packed, i));

    int32_t result_buf[256];
