morph_data morph_objects[MAX_MORPH_OBJECTS];

//returns ptr to data for this object, or NULL if none
morph_data *find_morph_data(object *obj)
{
	int i;

	#ifdef NEWDEMO
	if (Newdemo_state == ND_STATE_PLAYBACK) 
